import { Completion } from '@codemirror/autocomplete';

import { AutocompleteSuggestion } from '@dynatrace-sdk/client-query';

import { verifyQuery } from './dql-linter.js';
import {
  convertToMiddleEllipsis,
  fuzzyMatch,
  getFuzzyMatchFullLabelPosition,
  labelShouldBeTruncated,
} from './fuzzy-match.js';
import { getSuggestions } from './get-suggestions.js';
import { SuggestionPart } from './SuggestionPart.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { Text } from '../../../typography/text/Text.js';
import type {
  AutocompleteProvider,
  AutocompletionResult,
  Suggestion,
} from '../../base-code-editor/auto-completion/autocompletion.extension.js';

function getMatchPattern(content: string) {
  const match = content.match(/\W?([\w.]*)$/);
  const capture = match?.[1];
  return capture ?? '';
}

function hasInfo(suggestions: AutocompleteSuggestion[]): boolean {
  return suggestions.some((suggestion) =>
    suggestion.parts.some((part) => part.info !== undefined),
  );
}

type FilteredSuggestion = AutocompleteSuggestion & {
  score: number;
  startPos: number;
};

/**
 * Filters out and trims quote suggestions.
 * @param suggestions - suggestions list
 */
function removeQuoteSuggestions(
  suggestions: FilteredSuggestion[],
): FilteredSuggestion[] {
  const excludedSuggestions = ['"', '""', '"""', ' '];
  return suggestions
    .filter((elem) => !excludedSuggestions.includes(elem.suggestion))
    .map((elem) => {
      // trim trailing quotation marks
      const trimmed = elem.suggestion.replace(/"{1,3}$/, '');
      return { ...elem, suggestion: trimmed };
    })
    .filter((elem) => elem.suggestion.length > 0);
}

/**
 *  Filters the suggestions based on matching pattern and suggestions as well as the
 *  autocomplete trigger pattern.
 *
 * @param suggestions - suggestions for the pattern
 * @param pattern - pattern matched
 * @param requestCursorPosition - the request cursor position
 * @param cursorPosition - editor cursor position
 * @param disableFilter - flag for whether the autocomplete was triggered via ctrl+space or having a pattern length of 1 or less
 */
function filterSuggestions(
  suggestions: AutocompleteSuggestion[],
  pattern: string,
  requestCursorPosition: number,
  cursorPosition: number,
  disableFilter: boolean,
): Array<FilteredSuggestion> {
  return suggestions
    .reduce<Array<FilteredSuggestion>>((result, suggestion) => {
      // Check if the suggestion matches part of the pattern
      const matchResult = fuzzyMatch(pattern, suggestion.suggestion);
      const match =
        suggestion.alreadyTypedCharacters === 0 ? true : matchResult.match;
      // Give the match a score for sorting the suggestions based on the closest match to the pattern
      const score =
        suggestion.alreadyTypedCharacters === 0 ? 1 : matchResult.score;
      const startPos =
        suggestion.alreadyTypedCharacters === 0
          ? cursorPosition
          : requestCursorPosition - suggestion.alreadyTypedCharacters;
      if (suggestion.suggestion.length > 0 && (disableFilter || match)) {
        result.push({ ...suggestion, score, startPos });
      }
      return result;
    }, [])
    .sort((a, b) => b.score - a.score);
}

function getRequestString(
  autocompleteContent: string,
  patternLength: number,
  requestLength: number,
) {
  return autocompleteContent.slice(
    0,
    autocompleteContent.length - patternLength + requestLength,
  );
}

// max. number of suggestions fetched from autocomplete endpoint
const MAX_DATA_SUGGESTIONS = 10_000;

async function getFilteredSuggestions(
  autocompleteContent: string,
  patternLength: number,
  explicit: boolean,
): Promise<FilteredSuggestion[]> {
  const requestString = getRequestString(
    autocompleteContent,
    patternLength,
    explicit ? patternLength : 1,
  );
  const suggestions = await getSuggestions(
    requestString,
    requestString.length,
    MAX_DATA_SUGGESTIONS,
  );

  const pattern = autocompleteContent.slice(
    autocompleteContent.length - patternLength,
  );
  return filterSuggestions(
    suggestions,
    pattern,
    requestString.length,
    autocompleteContent.length,
    explicit,
  );
}

export const suggestionAutocompletion: AutocompleteProvider = async (
  context,
): Promise<AutocompletionResult | null> => {
  if (context.matchBefore(/[^\w.]/) && !context.explicit) {
    return null;
  }
  // For performance, only take the query up until the cursor position.
  // This allows the backend to be queried less often and the cache more often
  const autocompleteContent = context.state.doc
    .slice(0, context.pos)
    .toString();

  const pattern = getMatchPattern(autocompleteContent);

  const infoSuggestions = await getSuggestions(
    getRequestString(autocompleteContent, pattern.length, 0),
  );

  let filteredSuggestions = await getFilteredSuggestions(
    autocompleteContent,
    pattern.length,
    pattern.length <= 1,
  );

  if (filteredSuggestions.length === 0) {
    if (pattern.length > 1) {
      filteredSuggestions = await getFilteredSuggestions(
        autocompleteContent,
        pattern.length,
        true,
      );
    }
  }

  // Filter out suggestions (mainly quotes) if the cursor is within a string token and
  // the autocomplete query was not the full query (there are characters after the cursor).
  // This is necessary as we only send the autocomplete request with the query up to the cursor,
  // omitting text after the cursor (if present).
  // We still do want to show quotes if the cursor is at the end of the text and even within a string token.
  if (
    context.tokenBefore(['string']) !== null &&
    autocompleteContent.length !== context.state.doc.length
  ) {
    filteredSuggestions = removeQuoteSuggestions(filteredSuggestions);
  }

  /*
   * If there is only info (= no autocomplete suggestions), we still want to show this info.
   * However, this info is shown as a "section header", and CodeMirror does not allow sections without any items.
   * Hence, we need to return one empty autocomplete suggestion (which is then styled to be hidden).
   */
  if (filteredSuggestions.length === 0 && hasInfo(infoSuggestions)) {
    const emptySuggestion = infoSuggestions.find(
      (s) => s.suggestion.length === 0,
    );
    if (emptySuggestion) {
      filteredSuggestions.push({
        ...emptySuggestion,
        score: -99,
        startPos: context.pos,
      });
    }
  }

  if (filteredSuggestions.length === 0) {
    return null;
  }

  const autocompletePos = Math.min(
    ...filteredSuggestions.map((s) => s.startPos),
  );

  const section = infoSuggestions
    .filter((suggestion) => !suggestion.suggestion)
    .flatMap((suggestion) => suggestion.parts.map((part) => part.info))
    .filter((text) => !!text)
    .join(' ');

  return {
    suggestions: filteredSuggestions.map((suggestion): Suggestion => {
      const hasInfo = suggestion.parts.some((part) => !!part.info);

      const shouldBeTruncated = labelShouldBeTruncated(suggestion.suggestion);
      const middleEllipsisText = shouldBeTruncated
        ? convertToMiddleEllipsis(suggestion.suggestion)
        : suggestion.suggestion;

      const infoPopup = hasInfo
        ? () => {
            return (
              <Flex flexDirection="column" gap={16}>
                {suggestion.parts
                  .filter((part) => !!part.info)
                  .map((part) => (
                    <SuggestionPart key={part.info} suggestionPart={part} />
                  ))}
              </Flex>
            );
          }
        : undefined;

      return {
        ...suggestion,
        label: middleEllipsisText,
        section,
        apply: (view) => {
          view.dispatch({
            changes: {
              from: suggestion.startPos,
              to: autocompleteContent.length,
              insert: suggestion.suggestion,
            },
            selection: {
              anchor: suggestion.startPos + suggestion.suggestion.length,
            },
            userEvent: 'input.complete',
          });
        },

        popup: shouldBeTruncated
          ? () => (
              <>
                <Text fontStyle="code" as="p">
                  {suggestion.suggestion}
                </Text>
                {infoPopup ?? null}
              </>
            )
          : infoPopup,
      };
    }),
    from: autocompletePos,
    async reopen(completion: Completion & Partial<FilteredSuggestion>) {
      const queryToEnd = context.state.doc.slice(context.pos).toString();
      const completedQuery =
        autocompleteContent.slice(0, completion.startPos) +
        completion.suggestion +
        queryToEnd;

      const { valid = true } = (await verifyQuery(completedQuery)) ?? {};
      return !valid;
    },
    filter: false,
    getMatch: (completion: Completion & Partial<FilteredSuggestion>) => {
      return (
        getFuzzyMatchFullLabelPosition(pattern, completion.suggestion) ??
        fuzzyMatch(
          autocompleteContent.slice(autocompletePos),
          completion.suggestion ?? '',
        ).pos ??
        []
      );
    },
  };
};
